import React, { useEffect, useState, useRef } from "react";

import Header from "./components/Header";
import Home from "./sections/Home";
import About from "./sections/About";
import Work from "./sections/Work";
import Blog from "./sections/Blog";
import Contact from "./sections/Contact";

import './App.css';


function App() {

  let vh = window.innerHeight * 0.01;
  // Then we set the value in the --vh custom property to the root of the document
  document.documentElement.style.setProperty('--vh', `${vh}px`);

  const homeRef = useRef();
  const aboutRef = useRef();
  const workRef = useRef();
  const blogRef = useRef();
  const contactRef = useRef();
  const [activeSection, setActiveSection] = useState("home");
  useEffect(() => {
    window.addEventListener("scroll", (event) => {
      const scrollY = window.scrollY;
      if (scrollY >= contactRef?.current?.offsetTop - 60) {
        setActiveSection("contact");
      } else if (scrollY >= blogRef?.current?.offsetTop - 60) {
        setActiveSection("blog");
      } else if (scrollY >= workRef?.current?.offsetTop - 60) {
        setActiveSection("work");
      } else if (scrollY >= aboutRef?.current?.offsetTop - 60) {
        setActiveSection("about");
      } else {
        setActiveSection("home");
      }
    })
  }, [])
  return (
    <div className="app" id="app" >
      <Header active={activeSection} />
      <Home ref={homeRef} />
      <About ref={aboutRef} />
      <Work ref={workRef} />
      <Blog ref={blogRef} />
      <Contact ref={contactRef} />
    </div>
  );
}

export default App;
